svg.script:
(function() {
  // Game state
  const state = {
    status: 'idle', // idle, playing, gameOver
    birdX: 200,
    birdY: 120,
    birdDirection: 1,
    birdShakeOffset: { x: 0, y: 0 },
    birdHurt: false,
    birdHurtTimer: 0,
    humanX: 200,
    humanDirection: 1,
    humanReaction: 'none', // none, vomiting, crying, running
    humanReactionTimer: 0,
    humanOpacity: 1,
    humanRespawning: false,
    score: 0,
    level: 1,
    levelHits: 0,
    totalHits: 0,
    ammo: 5,
    maxAmmo: 5,
    birdLives: 3,
    poops: [],
    bullets: [],
    splats: [],
    keysPressed: new Set(),
    wingY: 0,
    wingDir: 1,
    startWingY: 0,
    startWingDir: 1,
    walkPhase: 0,
    levelUpVisible: false,
    levelUpTimer: 0
  };

  // Constants
  const MOVE_SPEED = 5;
  const BIRD_Y = 120;
  const HUMAN_Y = 480;
  const GROUND_Y = 500;
  const BOUNDARY_MARGIN = 40;
  const HITS_FOR_LEVEL = [0, 10, 25, 45, 70, 100];

  // Elements
  const bird = document.getElementById('bird');
  const birdBody = document.getElementById('birdBody');
  const birdBodyEllipse = document.getElementById('birdBodyEllipse');
  const birdHead = document.getElementById('birdHead');
  const human = document.getElementById('human');
  const humanHead = document.getElementById('humanHead');
  const wings = document.getElementById('wings');
  const startWings = document.getElementById('startWings');
  const painStars = document.getElementById('painStars');
  const vomitEffect = document.getElementById('vomitEffect');
  const cryEffect = document.getElementById('cryEffect');
  const poopsContainer = document.getElementById('poops');
  const splatsContainer = document.getElementById('splats');
  const bulletsContainer = document.getElementById('bullets');
  const startScreen = document.getElementById('startScreen');
  const gameOverScreen = document.getElementById('gameOverScreen');
  const startButton = document.getElementById('startButton');
  const restartButton = document.getElementById('restartButton');
  const scoreText = document.getElementById('scoreText');
  const levelText = document.getElementById('levelText');
  const nextLevelText = document.getElementById('nextLevelText');
  const finalScore = document.getElementById('finalScore');
  const finalLevel = document.getElementById('finalLevel');
  const ui = document.getElementById('ui');
  const gameContainer = document.getElementById('gameContainer');
  const levelUpOverlay = document.getElementById('levelUpOverlay');
  const levelUpText = document.getElementById('levelUpText');

  // Limb elements
  const humanFrontLeg = document.getElementById('humanFrontLeg');
  const humanBackLeg = document.getElementById('humanBackLeg');
  const humanFrontArm = document.getElementById('humanFrontArm');
  const humanBackArm = document.getElementById('humanBackArm');

  let poopId = 0;
  let bulletId = 0;
  let splatId = 0;
  let lastShootTime = 0;
  let nextShootInterval = 3000 + Math.random() * 3000;

  function startGame() {
    state.status = 'playing';
    state.birdX = 200;
    state.humanX = 200;
    state.humanDirection = 1;
    state.humanReaction = 'none';
    state.humanOpacity = 1;
    state.humanRespawning = false;
    state.birdHurt = false;
    state.birdShakeOffset = { x: 0, y: 0 };
    state.score = 0;
    state.level = 1;
    state.levelHits = 0;
    state.totalHits = 0;
    state.ammo = 5;
    state.birdLives = 3;
    state.poops = [];
    state.bullets = [];
    state.splats = [];
    state.levelUpVisible = false;
    poopsContainer.innerHTML = '';
    splatsContainer.innerHTML = '';
    bulletsContainer.innerHTML = '';
    startScreen.setAttribute('visibility', 'hidden');
    gameOverScreen.setAttribute('visibility', 'hidden');
    levelUpOverlay.setAttribute('visibility', 'hidden');
    ui.setAttribute('visibility', 'visible');
    gameContainer.setAttribute('visibility', 'visible');
    human.setAttribute('opacity', '1');
    vomitEffect.setAttribute('visibility', 'hidden');
    cryEffect.setAttribute('visibility', 'hidden');
    painStars.setAttribute('visibility', 'hidden');
    birdBodyEllipse.setAttribute('fill', '#4A4A4A');
    birdHead.setAttribute('fill', '#4A4A4A');
    updateUI();
    lastShootTime = Date.now();
    nextShootInterval = 3000 + Math.random() * 3000;
  }

  function gameOver() {
    state.status = 'gameOver';
    finalScore.textContent = 'Final Score: ' + state.score;
    finalLevel.textContent = 'Level Reached: ' + state.level;
    gameOverScreen.setAttribute('visibility', 'visible');
  }

  function getHitsForNextLevel() {
    if (state.level >= HITS_FOR_LEVEL.length - 1) return 999;
    return HITS_FOR_LEVEL[state.level];
  }

  function updateUI() {
    scoreText.textContent = 'Score: ' + state.score;
    levelText.textContent = 'Level: ' + state.level;

    const hitsNeeded = getHitsForNextLevel() - state.totalHits;
    if (state.level >= 5) {
      nextLevelText.textContent = 'Max Level!';
    } else {
      nextLevelText.textContent = hitsNeeded + ' more to Level ' + (state.level + 1);
    }

    for (let i = 0; i < 3; i++) {
      document.getElementById('heart' + i).setAttribute('fill', i < state.birdLives ? '#FF0000' : '#ccc');
    }
    for (let i = 0; i < 5; i++) {
      document.getElementById('ammo' + i).setAttribute('fill', i < state.ammo ? '#8B4513' : '#ddd');
    }
  }

  function calculateLevel(hits) {
    for (let i = HITS_FOR_LEVEL.length - 1; i >= 0; i--) {
      if (hits >= HITS_FOR_LEVEL[i]) return i + 1;
    }
    return 1;
  }

  function showLevelUp(level) {
    levelUpText.textContent = 'LEVEL ' + level + '!';
    levelUpOverlay.setAttribute('visibility', 'visible');
    state.levelUpVisible = true;
    state.levelUpTimer = 120; // 2 seconds at 60fps
  }

  function spawnPoop() {
    if (state.ammo <= 0) return;
    state.ammo--;
    const poop = {
      id: poopId++,
      x: state.birdX,
      y: BIRD_Y + 15,
      speed: 3 + state.level * 0.5
    };
    state.poops.push(poop);
    const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    g.setAttribute('id', 'poop' + poop.id);
    g.innerHTML = '<ellipse cx="0" cy="0" rx="8" ry="6" fill="#8B4513"/><ellipse cx="0" cy="-5" rx="6" ry="5" fill="#8B4513"/><ellipse cx="0" cy="-9" rx="4" ry="4" fill="#8B4513"/><ellipse cx="0" cy="-12" rx="2" ry="2" fill="#8B4513"/>';
    poopsContainer.appendChild(g);
    updateUI();
  }

  function spawnSplat(x, y, isHit) {
    const splat = {
      id: splatId++,
      x: x,
      y: y,
      scale: 1,
      opacity: 1,
      timer: 30
    };
    state.splats.push(splat);
    const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    g.setAttribute('id', 'splat' + splat.id);
    const color = isHit ? '#6B4423' : '#8B4513';
    g.innerHTML = '<ellipse cx="0" cy="0" rx="15" ry="8" fill="' + color + '" opacity="0.9"/>' +
      '<ellipse cx="-10" cy="-3" rx="6" ry="4" fill="' + color + '" opacity="0.7"/>' +
      '<ellipse cx="12" cy="2" rx="5" ry="3" fill="' + color + '" opacity="0.7"/>' +
      '<ellipse cx="5" cy="-5" rx="4" ry="3" fill="' + color + '" opacity="0.6"/>' +
      '<ellipse cx="-5" cy="4" rx="3" ry="2" fill="' + color + '" opacity="0.5"/>';
    splatsContainer.appendChild(g);
  }

  function spawnBullet() {
    const bullet = {
      id: bulletId++,
      x: state.humanX,
      y: HUMAN_Y - 30,
      speed: 4
    };
    state.bullets.push(bullet);
    const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    g.setAttribute('id', 'bullet' + bullet.id);
    g.innerHTML = '<ellipse cx="0" cy="0" rx="3" ry="6" fill="#333"/><path d="M -3 0 L 0 -8 L 3 0" fill="#8B8B8B"/>';
    bulletsContainer.appendChild(g);
  }

  function triggerHumanReaction() {
    const reactions = ['vomiting', 'crying', 'running'];
    state.humanReaction = reactions[Math.floor(Math.random() * reactions.length)];
    state.humanReactionTimer = 90; // 1.5 seconds

    if (state.humanReaction === 'vomiting') {
      vomitEffect.setAttribute('visibility', 'visible');
    } else if (state.humanReaction === 'crying') {
      cryEffect.setAttribute('visibility', 'visible');
    }
  }

  function triggerBirdHurt() {
    state.birdHurt = true;
    state.birdHurtTimer = 20;
    painStars.setAttribute('visibility', 'visible');
    birdBodyEllipse.setAttribute('fill', '#FF4444');
    birdHead.setAttribute('fill', '#FF4444');
  }

  function updateBird() {
    let dx = 0;
    if (state.keysPressed.has('arrowleft') || state.keysPressed.has('a')) dx -= MOVE_SPEED;
    if (state.keysPressed.has('arrowright') || state.keysPressed.has('d')) dx += MOVE_SPEED;

    if (dx !== 0) {
      state.birdX = Math.max(BOUNDARY_MARGIN, Math.min(400 - BOUNDARY_MARGIN, state.birdX + dx));
      state.birdDirection = dx > 0 ? 1 : -1;
    }

    // Bird hurt shake animation
    if (state.birdHurt) {
      state.birdHurtTimer--;
      const shakePhase = state.birdHurtTimer % 4;
      if (shakePhase === 0) state.birdShakeOffset = { x: -4, y: -2 };
      else if (shakePhase === 1) state.birdShakeOffset = { x: 4, y: 2 };
      else if (shakePhase === 2) state.birdShakeOffset = { x: -3, y: 1 };
      else state.birdShakeOffset = { x: 3, y: -1 };

      if (state.birdHurtTimer <= 0) {
        state.birdHurt = false;
        state.birdShakeOffset = { x: 0, y: 0 };
        painStars.setAttribute('visibility', 'hidden');
        birdBodyEllipse.setAttribute('fill', '#4A4A4A');
        birdHead.setAttribute('fill', '#4A4A4A');
      }
    }

    const offsetX = state.birdShakeOffset.x;
    const offsetY = state.birdShakeOffset.y;
    bird.setAttribute('transform', 'translate(' + (state.birdX + offsetX) + ', ' + (BIRD_Y + offsetY) + ') scale(' + state.birdDirection + ', 1)');

    // Wing animation
    state.wingY += state.wingDir * 2;
    if (state.wingY > 6) state.wingDir = -1;
    if (state.wingY < -8) state.wingDir = 1;
    wings.setAttribute('transform', 'translate(0, ' + state.wingY + ')');
  }

  function updateHuman() {
    // Handle reactions
    if (state.humanReaction !== 'none') {
      state.humanReactionTimer--;

      if (state.humanReaction === 'running') {
        // Run faster in one direction
        state.humanX += 4 * state.humanDirection;
      }

      if (state.humanReactionTimer <= 0) {
        state.humanReaction = 'none';
        vomitEffect.setAttribute('visibility', 'hidden');
        cryEffect.setAttribute('visibility', 'hidden');
        // Start fade out
        state.humanRespawning = true;
        state.humanOpacity = 1;
      }
      return;
    }

    // Handle respawn fade
    if (state.humanRespawning) {
      state.humanOpacity -= 0.05;
      human.setAttribute('opacity', state.humanOpacity.toString());

      if (state.humanOpacity <= 0) {
        // Respawn at random position
        state.humanX = 100 + Math.random() * 200;
        state.humanDirection = Math.random() > 0.5 ? 1 : -1;
        state.humanRespawning = false;
        state.humanOpacity = 1;
        human.setAttribute('opacity', '1');
      }
      return;
    }

    const speed = 1.5 + state.level * 0.3;
    state.humanX += speed * state.humanDirection;

    if (state.humanX >= 400 - BOUNDARY_MARGIN) {
      state.humanX = 400 - BOUNDARY_MARGIN;
      state.humanDirection = -1;
    } else if (state.humanX <= BOUNDARY_MARGIN) {
      state.humanX = BOUNDARY_MARGIN;
      state.humanDirection = 1;
    }

    human.setAttribute('transform', 'translate(' + state.humanX + ', ' + HUMAN_Y + ') scale(' + state.humanDirection + ', 1)');

    // Walking animation
    state.walkPhase += 0.15;
    const swing = Math.sin(state.walkPhase) * 18;
    humanFrontLeg.setAttribute('transform', 'rotate(' + swing + ', -3, 5)');
    humanBackLeg.setAttribute('transform', 'rotate(' + (-swing) + ', 3, 5)');
    humanFrontArm.setAttribute('transform', 'rotate(' + (-swing) + ', 6, -12)');
    humanBackArm.setAttribute('transform', 'rotate(' + swing + ', -4, -12)');

    // Shooting
    const now = Date.now();
    if (now - lastShootTime > nextShootInterval) {
      spawnBullet();
      lastShootTime = now;
      nextShootInterval = 3000 + Math.random() * 3000;
    }
  }

  function updatePoops() {
    const toRemove = [];
    state.poops.forEach(poop => {
      poop.y += poop.speed;
      const el = document.getElementById('poop' + poop.id);
      if (el) {
        el.setAttribute('transform', 'translate(' + poop.x + ', ' + poop.y + ')');
      }

      if (poop.y >= GROUND_Y - 10) {
        const hit = Math.abs(poop.x - state.humanX) < 25 && state.humanReaction === 'none' && !state.humanRespawning;

        // Spawn splat animation
        spawnSplat(poop.x, GROUND_Y - 5, hit);

        if (hit) {
          state.totalHits++;
          const newLevel = calculateLevel(state.totalHits);
          if (newLevel > state.level) {
            state.level = newLevel;
            state.levelHits = 1;
            showLevelUp(newLevel);
          } else {
            state.levelHits++;
          }
          state.score += state.level * 10;
          triggerHumanReaction();
          updateUI();
        }
        toRemove.push(poop.id);
      }
    });

    toRemove.forEach(id => {
      state.poops = state.poops.filter(p => p.id !== id);
      const el = document.getElementById('poop' + id);
      if (el) el.remove();
    });
  }

  function updateSplats() {
    const toRemove = [];
    state.splats.forEach(splat => {
      splat.timer--;
      splat.opacity = splat.timer / 30;
      splat.scale = 1 + (1 - splat.timer / 30) * 0.5;

      const el = document.getElementById('splat' + splat.id);
      if (el) {
        el.setAttribute('transform', 'translate(' + splat.x + ', ' + splat.y + ') scale(' + splat.scale + ')');
        el.setAttribute('opacity', splat.opacity.toString());
      }

      if (splat.timer <= 0) {
        toRemove.push(splat.id);
      }
    });

    toRemove.forEach(id => {
      state.splats = state.splats.filter(s => s.id !== id);
      const el = document.getElementById('splat' + id);
      if (el) el.remove();
    });
  }

  function updateBullets() {
    const toRemove = [];
    state.bullets.forEach(bullet => {
      bullet.y -= bullet.speed;
      const el = document.getElementById('bullet' + bullet.id);
      if (el) {
        el.setAttribute('transform', 'translate(' + bullet.x + ', ' + bullet.y + ')');
      }

      if (bullet.y <= BIRD_Y + 10) {
        const hit = Math.abs(bullet.x - state.birdX) < 30;
        if (hit && !state.birdHurt) {
          state.birdLives--;
          triggerBirdHurt();
          updateUI();
          if (state.birdLives <= 0) {
            gameOver();
          }
        }
        toRemove.push(bullet.id);
      }
    });

    toRemove.forEach(id => {
      state.bullets = state.bullets.filter(b => b.id !== id);
      const el = document.getElementById('bullet' + id);
      if (el) el.remove();
    });
  }

  function updateLevelUp() {
    if (state.levelUpVisible) {
      state.levelUpTimer--;
      const opacity = Math.min(1, state.levelUpTimer / 30);
      const translateY = (120 - state.levelUpTimer) * 0.5;
      levelUpText.setAttribute('opacity', opacity.toString());
      levelUpText.setAttribute('transform', 'translate(0, ' + translateY + ')');

      if (state.levelUpTimer <= 0) {
        state.levelUpVisible = false;
        levelUpOverlay.setAttribute('visibility', 'hidden');
        levelUpText.setAttribute('opacity', '1');
        levelUpText.setAttribute('transform', '');
      }
    }
  }

  function updateStartScreenBird() {
    // Wing flapping on start screen
    state.startWingY += state.startWingDir * 2;
    if (state.startWingY > 6) state.startWingDir = -1;
    if (state.startWingY < -8) state.startWingDir = 1;
    startWings.setAttribute('transform', 'translate(0, ' + state.startWingY + ')');
  }

  let lastRegenTime = 0;
  function gameLoop(timestamp) {
    if (state.status === 'playing') {
      updateBird();
      updateHuman();
      updatePoops();
      updateSplats();
      updateBullets();
      updateLevelUp();

      if (timestamp - lastRegenTime > 2000) {
        if (state.ammo < state.maxAmmo) {
          state.ammo++;
          updateUI();
        }
        lastRegenTime = timestamp;
      }
    } else if (state.status === 'idle') {
      updateStartScreenBird();
    }
    requestAnimationFrame(gameLoop);
  }

  // Event listeners
  document.addEventListener('keydown', function(e) {
    const key = e.key.toLowerCase();
    if (['arrowleft', 'arrowright', 'a', 'd', ' '].includes(key)) {
      e.preventDefault();
      state.keysPressed.add(key);
      if (key === ' ' && state.status === 'playing') {
        spawnPoop();
      }
    }
  });

  document.addEventListener('keyup', function(e) {
    state.keysPressed.delete(e.key.toLowerCase());
  });

  // Touch controls
  const svg = document.querySelector('svg');
  svg.addEventListener('touchstart', function(e) {
    if (state.status !== 'playing') return;
    e.preventDefault();
    const touch = e.touches[0];
    const rect = svg.getBoundingClientRect();
    const x = touch.clientX - rect.left;
    const width = rect.width;

    if (x < width / 3) {
      state.keysPressed.add('arrowleft');
    } else if (x > width * 2 / 3) {
      state.keysPressed.add('arrowright');
    } else {
      spawnPoop();
    }
  });

  svg.addEventListener('touchend', function(e) {
    state.keysPressed.delete('arrowleft');
    state.keysPressed.delete('arrowright');
  });

  startButton.addEventListener('click', startGame);
  restartButton.addEventListener('click', startGame);

  // Initialize
  ui.setAttribute('visibility', 'hidden');
  gameContainer.setAttribute('visibility', 'hidden');
  requestAnimationFrame(gameLoop);
})();
